  return { json: { htmlContent: "<p>No hay datos que procesar.</p>" } };
}

// --- Obtener el tipo de reporte (Daily, Weekly, etc.) ---
let reportType = "General";
try {
  // Intentamos leer el tipo desde el primer item del Loop de Credenciales
  reportType = $("Credentials Loop").first().json["type"] || "General";
} catch (error) {
  // Si falla, usamos el valor por defecto
}

const allQueries = allItems.map(item => item.json);
let validHtmlParts = []; // Aquí acumularemos solo los reportes que tengan datos

// --- Configuración Visual (Estilos para Teams/Email) ---
const MAX_ROWS = 20;
const MAX_COLS = 6;

const styles = {
  table: 'border-collapse: collapse; margin-bottom: 10px; width: 100%;', 
  th: 'padding: 5px; text-align: left; font-weight: bold; border: 1px solid #ddd;', 
  td: 'padding: 5px; vertical-align: top; border: 1px solid #ddd;',
  p: 'font-size: 14px; margin: 0 0 10px 0;',
  p_notice: 'font-size: 12px; font-style: italic; color: #666;',
  h3: 'margin-bottom: 5px; font-size: 16px; font-weight: bold; color: #000;',
  pre: 'font-family: monospace; white-space: pre-wrap; word-wrap: break-word; font-size: 11px; margin-top: 0;',
  hr: 'border: 0; border-top: 1px solid #ccc; margin: 15px 0;',
  queryLabel: 'font-size: 10px; font-weight: bold; text-transform: uppercase; margin-bottom: 0; margin-top: 10px;',
  mainTitle: 'font-size: 24px; font-weight: bold; color: #000; margin-bottom: 20px; border-bottom: 2px solid #000; padding-bottom: 10px;'
};

// --- Construcción del Título Principal ---
const reportTypeFormatted = reportType.charAt(0).toUpperCase() + reportType.slice(1);
let combinedHtml = `<h1 style="${styles.mainTitle}">Resultados de revisión ${reportTypeFormatted}</h1>`;

// --- Bucle Principal sobre cada Query ---
for (const item of allQueries) {
  const results = item.result;

  // 1. FILTRO DE RESULTADOS VACÍOS
  // Verificamos si results es null, vacío o un array con un objeto vacío.
  let isEmpty = false;
  if (!results) {
    isEmpty = true;
  } else if (Array.isArray(results) && results.length === 0) {
    isEmpty = true;
  } else if (Array.isArray(results) && results.length === 1) {
    const firstItem = results[0];
    if (firstItem === null || (typeof firstItem === 'object' && Object.keys(firstItem).length === 0)) {
      isEmpty = true;
    }
  }

  // REGLA: "No se muestre nada si el punto no da resultado"
  if (isEmpty) {
    continue; // Saltamos a la siguiente iteración inmediatamente
  }

  // --- Si llegamos aquí, ES PORQUE HAY DATOS PARA MOSTRAR ---
  let itemHtml = "";

  // Título del Punto
  itemHtml += `<h3 style="${styles.h3}">Punto ${item.queryId}: ${item.description || "Sin descripción"}</h3>`;

  // 2. CONSTRUCCIÓN DE LA TABLA
  let data = results;
  let limitedRows = false;
  let limitedCols = false;

  // Lógica de límites (filas)
  if (results.length > MAX_ROWS) {
    data = results.slice(0, MAX_ROWS);
    limitedRows = true;
  }

  // Obtener cabeceras
  let headers = Object.keys(data[0] || {});

  // Lógica de límites (columnas)
  if (headers.length > MAX_COLS) {
    headers = headers.slice(0, MAX_COLS);
    limitedCols = true;
  }

  // HTML de la Tabla
  itemHtml += `<table border="1" style="${styles.table}">`;
  itemHtml += '<thead><tr>';
  for (const header of headers) itemHtml += `<th style="${styles.th}">${header}</th>`;
  itemHtml += "</tr></thead>";

  itemHtml += "<tbody>";
  for (const row of data) {
    itemHtml += "<tr>";
    for (const header of headers) {
      // Manejo seguro de null/undefined y escape de caracteres HTML
      const value = (row[header] === null || typeof row[header] === "undefined") 
        ? "" 
        : String(row[header]).replace(/</g, '&lt;').replace(/>/g, '&gt;');
      itemHtml += `<td style="${styles.td}">${value}</td>`;
    }
    itemHtml += "</tr>";
  }
  itemHtml += "</tbody></table>";

  // Avisos de recorte de datos
  let notices = "";
  if (limitedRows) notices += `(Se muestran ${MAX_ROWS} filas de ${results.length}). `;
  if (limitedCols) notices += `(Se muestran ${MAX_COLS} columnas de ${Object.keys(results[0]).length}).`;
  if (notices) itemHtml += `<p style="${styles.p_notice}">${notices.trim()}</p>`;

  // 3. LÓGICA DE PATRONES (1, 2, 3)
  // Convertimos a string por seguridad
  const pattern = String(item.pattern || "0").trim();

  // REGLA: Solo mostramos queries si el patrón es '2'
  if (pattern === '2') {
    const selectQuery = item.revisionQuery || "(No se proporcionó SELECT)";
    const correctionQuery = item.correctionQuery || "(No se proporcionó UPDATE)";
    const combinedQueryText = `
    -- SELECT --
    ${selectQuery}

    -- UPDATE --
    ${correctionQuery}
    `.trim();

    itemHtml += `<div style="margin-top: 10px;">`;
    itemHtml += `<p style="${styles.queryLabel}">Script:</p>`;
    // Renderizamos UNA SOLA caja <pre> con todo el contenido
    itemHtml += `<pre style="${styles.pre}">${combinedQueryText}</pre>`;
    itemHtml += `</div>`;
  }
  // Pattern 1 y 3 (y otros) no muestran nada aquí.

  validHtmlParts.push(itemHtml);
}

// --- GENERACIÓN FINAL ---

if (validHtmlParts.length === 0) {
  // Caso: Se ejecutó el flujo, pero todas las queries vinieron vacías.
  // Mensaje final indicando que todo está limpio.
  combinedHtml += `<p style="${styles.p}">No se encontraron novedades ni datos para revisar en este entorno el día de hoy.</p>`;
} else {
  // Unimos todas las partes válidas con un separador <hr>
  combinedHtml += validHtmlParts.join(`<hr style="${styles.hr}">`);
}

// Retornamos el contenido para el siguiente nodo (Teams/Email)
const parentPairedItem = items.length > 0 ? items[0].pairedItem : undefined;

return { 
    json: { htmlContent: combinedHtml },
    pairedItem: parentPairedItem
};

